// Auto-detect and normalize binary keys
const body = $json.body || {};
const incomingBinary = items[0].binary || {};

let pdfKey = null;
let voiceKey = null;

// Find PDF and voice files
for (const k of Object.keys(incomingBinary)) {
  const b = incomingBinary[k] || {};
  const fn = (b.fileName || '').toLowerCase();
  const mt = (b.mimeType || '').toLowerCase();

  if (!pdfKey && (mt.includes('pdf') || fn.endsWith('.pdf') || k.toLowerCase().includes('pdf'))) {
    pdfKey = k;
  }
  if (!voiceKey && (mt.startsWith('audio') || fn.match(/\.(wav|mp3|m4a|ogg)$/i) || k.toLowerCase().includes('voice'))) {
    voiceKey = k;
  }
}

// Fallback to common names
if (!pdfKey) pdfKey = ['pdf_file', 'pdf', 'file'].find(k => incomingBinary[k]);
if (!voiceKey) voiceKey = ['voice_file', 'voice', 'voice_sample'].find(k => incomingBinary[k]);

const out = {
  json: {
    language: (body.language || 'EN').toUpperCase(),
    use_custom_voice: Boolean(body.use_custom_voice),
    detected: { pdfKey, voiceKey }
  },
  binary: {}
};

if (pdfKey && incomingBinary[pdfKey]) out.binary.pdf_file = incomingBinary[pdfKey];
if (voiceKey && incomingBinary[voiceKey]) out.binary.voice_file = incomingBinary[voiceKey];

return [out];

// Fix binary data format
const incoming = items[0].binary || {};
const outBinary = {};

function fixBinary(obj, defaultName, defaultMime) {
  if (!obj) return null;
  if (obj.data) return obj; // Already correct
  if (obj.id) return obj; // n8n reference
  if (typeof obj === 'string') return { data: obj, fileName: defaultName, mimeType: defaultMime };
  return null;
}

// Process PDF
if (incoming.pdf_file) {
  outBinary.pdf_file = fixBinary(incoming.pdf_file, 'upload.pdf', 'application/pdf');
  if (outBinary.pdf_file && !outBinary.pdf_file.fileName) outBinary.pdf_file.fileName = 'upload.pdf';
}

// Process voice file
if (incoming.voice_file) {
  outBinary.voice_file = fixBinary(incoming.voice_file, 'voice.wav', 'audio/wav');
  if (outBinary.voice_file && !outBinary.voice_file.fileName) outBinary.voice_file.fileName = 'voice.wav';
}

return [{ json: items[0].json, binary: outBinary }];

// Final response formatting
const resp = items[0];
const hasAudio = resp.binary && resp.binary.response_audio && resp.binary.response_audio.data;

return [{
  json: {
    success: hasAudio,
    message: hasAudio ? 'Audio generated successfully' : 'Audio generation failed',
    language: $json.language,
    custom_voice_used: $json.use_custom_voice,
    detected: $json.detected
  },
  binary: resp.binary
}];
